/// <summary>
/// Data provider for the Hugo Boss Retail Statement Payment Summary report.
/// Queries RetailStatementJour (header) joined to RetailTransactionPaymentTrans (payment lines),
/// RetailChannelView (store name), and RetailStoreTenderTypeTable (tender type name).
/// Aggregates AmountTendered per Store, Payment Method, and Currency for
/// posted Financial statements (StatementType = 1).
/// </summary>
[SRSReportParameterAttribute(classStr(HBRetailStatementPaymentContract))]
class HBRetailStatementPaymentDP extends SRSReportDataProviderBase
{
    HBRetailStatementPaymentTmp tmpTable;

}

Method.Source:
/// <summary>
/// Returns the temporary table populated by processReport().
/// </summary>
[SRSReportDataSetAttribute(tableStr(HBRetailStatementPaymentTmp))]
public HBRetailStatementPaymentTmp getTmp()
{
    select tmpTable;
    return tmpTable;
}

/// <summary>
/// Main report processing logic. Reads contract parameters, queries the
/// confirmed schema tables, aggregates payment amounts, and populates
/// the temporary table for the RDL to consume.
/// </summary>
public void processReport()
{
    HBRetailStatementPaymentContract    contract;
    TransDate                           fromDate;
    TransDate                           toDate;
    List                                storeIds;
    ListEnumerator                      storeEnum;
    str                                 storeRangeValue;

    RetailStatementJour                 stmtJour;
    RetailTransactionPaymentTrans       paymentTrans;

    Query                               query;
    QueryBuildDataSource                qbdsLine;
    QueryBuildDataSource                qbdsJour;
    QueryRun                            queryRun;

    // Lookup tables for names
    RetailChannelView                   channelView;
    RetailStoreTenderTypeTable          tenderType;

    contract    = this.parmDataContract() as HBRetailStatementPaymentContract;
    fromDate    = contract.parmFromDate();
    toDate      = contract.parmToDate();
    storeIds    = contract.parmStoreIds();

    // Build the store range value as comma-separated string for query filter
    storeRangeValue = '';
    if (storeIds && storeIds.elements() > 0)
    {
        storeEnum = storeIds.getEnumerator();
        while (storeEnum.moveNext())
        {
            if (storeRangeValue)
            {
                storeRangeValue += ',';
            }
            storeRangeValue += storeEnum.current();
        }
    }

    // Use while select with group by for aggregation
    // The D365 company context (DataAreaId) is handled automatically in X++
    // Detail table: RetailTransactionPaymentTrans
    // Column mapping: TenderType (not TenderTypeId), AmountTendered (not CountedAmount), Store (not StoreId)
    while select sum(AmountTendered)
        from paymentTrans
        group by paymentTrans.Store, paymentTrans.TenderType, paymentTrans.Currency
        join stmtJour
            where stmtJour.StatementId  == paymentTrans.StatementId
               && stmtJour.dataAreaId   == paymentTrans.dataAreaId
               && stmtJour.StatementType == RetailStatementType::Financial
               && stmtJour.StatementDate >= fromDate
               && stmtJour.StatementDate <= toDate
    {
        // Apply store filter if specified
        if (storeRangeValue && !SysQuery::findValue(storeRangeValue, paymentTrans.Store))
        {
            continue;
        }

        // Look up store name from RetailChannelView
        select firstonly Name from channelView
            where channelView.RetailChannelId == paymentTrans.Store;

        // Look up tender type name from RetailStoreTenderTypeTable
        // Note: detail column is TenderType, lookup column is TenderTypeId
        select firstonly Name from tenderType
            where tenderType.TenderTypeId == paymentTrans.TenderType
               && tenderType.Channel      == channelView.RecId
               && tenderType.dataAreaId   == paymentTrans.dataAreaId;

        tmpTable.clear();
        tmpTable.StoreId        = paymentTrans.Store;
        tmpTable.StoreName      = channelView.Name;
        tmpTable.TenderTypeId   = paymentTrans.TenderType;
        tmpTable.TenderTypeName = tenderType.Name;
        tmpTable.CurrencyCode   = paymentTrans.Currency;
        tmpTable.TotalAmount    = paymentTrans.AmountTendered;
        tmpTable.insert();
    }
}
